VALUES
  ('cpa-moex-01081', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '海角公司產銷涼鞋，每雙售價為$100、變動製造成本$45、變動行銷費用$10，已分攤固定製造成本 為$15。目前有閒置產能30,000雙，今接到20,000雙涼鞋之一次性訂單，每雙報價$60，此訂單並不 會影響目前正常之銷量。若接受此訂單無需增加任何行銷費用。試問接受此訂單，公司利潤將增加 多少？', '["$0", "$100,000", "$300,000", "$450,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01082', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '若不考慮所得稅效果，下列何者於制定決策時可能屬於攸關成本？ 甲、固定成本 乙、折舊費用', '["僅甲可能為攸關成本", "僅乙可能為攸關成本", "甲、乙均可能為攸關成本", "甲、乙均不可能為攸關成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01083', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '關於評估長期投資方案時，下列敘述何者正確？', '["還本期間法（payback period method）已考慮還本後的現金流量", "折現還本期間法（discounted payback period method）只能使用在每一期現金流量相同的情況下", "淨現值大於零的投資方案，獲利指數一定會大於零", "淨現值法（net present value method）與內部報酬率法（internal rate of return method）對於資金再投 資的假設相同"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01084', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '請回答下列二題。臺北藥廠擬購入一台價值$1,000,000的製藥機器，預期可使用10年，採直線法提 列折舊，無殘值，預計所生產的新藥每年將增加現金流入$150,000（稅前），設所得稅率為20%，此 投資計畫的還本期間為幾年？', '["8.33", "7.14", "6.67", "5.00"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01085', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '承上題，以平均投資金額為基礎之會計報酬率為何？', '["24%", "12%", "10%", "8%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01086', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '甲公司全年度預計直接人工時數為 20,000 小時、機器小時為 30,000 小時及預計製造費用總額為 $90,000，包含監工成本$30,000（成本動因為直接人工小時）與電力成本$60,000（成本動因為機器小 時）。現有一張訂單，依直接人工小時分攤製造費用時，製造費用成本為$4,050；若改採作業基礎成 本制分攤製造費用時，分攤之製造費用將減少$300，試問這張訂單耗用多少機器小時？', '["900小時", "1,200小時", "1,875小時", "2,000小時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01087', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '下列有關作業基礎成本制度（activity-based costing systems）之敘述，何者正確？', '["是一種只適合製造業的成本分攤法", "當產品相似度高時，作業基礎成本制度會提供較不正確的成本資訊", "當各產品耗用的資源種類繁多，且耗用服務性資源相似時，應使用作業基礎成本制度所提供的資訊", "可協助改善產品設計與生產效率"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01088', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '創新公司有甲、乙兩個部門，甲部門生產半成品，乙部門進一步將半成品組裝為成品。根據過去的 年度資料，甲部門的製造成本$6,000,000，將一部分半成品賣到市場的營收$4,000,000，其餘部分按 市價內部移轉給乙部門的收入$6,000,000。乙部門的加工成本$1,500,000，營收$7,200,000，乙部門的 主管會採取何種決策，並基於何種理由？', '["由於部門的營業淨利為正，所以繼續維持目前作法", "雖然部門的營業淨利為正，但是仍會設法提高售價或降低成本，以增加公司的淨利", "由於營業淨利為負，所以設法提高售價或降低成本，以降低部門的虧損", "由於營業淨利為負，所以設法降低甲部門的內部移轉價格，以提升公司整體淨利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01089', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '如果經濟訂購量（economic order quantity）的決策模式，只設定在同時使訂購成本（ordering costs） 及持有成本（carrying costs）之總和極小化，則下列何者是此一決策模式所隱含的假設？', '["不會發生缺貨", "容許發生數量折扣", "每次訂購成本及單位持有成本為可變動的", "容許在每次的再訂購時點，可有不同的訂購數量"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01090', 'cpa', 'cpa-moex-105-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '木柵公司之製造與採購作業採及時制度（JIT），因此公司會計紀錄採倒流式成本法（backflush costing），分錄之記錄點設於製成品完工及產品銷售時。該公司10月份之直接材料並無期初存貨， 10月份亦無任何期初與期末之在製品存貨，10月份之其餘相關資訊如下： 產品單位售價  $12 銷售單位數  75,000 製造單位數  80,000 加工成本  $90,400 購入直接材料  $250,400 請問10月份製成品完工時應有之分錄為何？', '["銷貨成本    319,500 存貨：原料及在製品    234,750 已分攤加工成本    84,750", "製成品  319,500 存貨：原料及在製品    234,750 已分攤加工成本    84,750", "製成品  340,800 存貨：原料及在製品    250,400 已分攤加工成本    90,400", "製成品  340,800 應付帳款    250,400 已分攤加工成本    90,400"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:12+00:00", "source_pdf_sha1": "c88a34846fb7", "answer_pdf_sha1": "02a373102f08", "source_family": "moex-gov-tw", "moex": {"exam_code": "105130", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "105", "exam_name": "105年會計師不動產估價師專利師民間之公證人考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
